import { Component, signal } from '@angular/core';
import { AXHierarchyChartComponent } from '@acorex/charts/hierarchy-chart';
import { AXHierarchyChartData } from '@acorex/charts/hierarchy-chart';
import { AXHierarchyChartOption } from '@acorex/charts/hierarchy-chart';
import { AXHierarchyChartClickEvent } from '@acorex/charts/hierarchy-chart';

@Component({
  template: `
    <div class="showcase-container">
      <h2>Interactive Hierarchy Chart</h2>
      <ax-hierarchy-chart 
        [data]="showcaseData()" 
        [options]="showcaseOptions()"
        (itemClick)="onNodeClick($event)"
      />
      <div class="hierarchy-info">
        <p>Click on nodes to interact with the organizational structure</p>
      </div>
    </div>
  `,
  imports: [AXHierarchyChartComponent],
  styles: [`
    .showcase-container {
      padding: 2rem;
      background: var(--ax-sys-color-lightest-surface);
      border-radius: 8px;
    }
    .hierarchy-info {
      margin-top: 1rem;
      text-align: center;
      color: var(--ax-sys-color-on-lightest-surface);
    }
  `]
})
export class HierarchyChartShowcaseComponent {
  showcaseData = signal<AXHierarchyChartData>({
    id: 'ceo',
    name: 'Alex Thompson',
    subtitle: 'Chief Executive Officer',
    icon: 'fa-user-tie',
    tooltip: 'CEO with 15+ years experience',
    color: '#2c3e50',
    isExpanded: true,
    children: [
      {
        id: 'cto',
        name: 'Maria Rodriguez',
        subtitle: 'Chief Technology Officer',
        icon: 'fa-laptop-code',
        tooltip: 'CTO leading technology strategy',
        color: '#3498db',
        children: [
          {
            id: 'eng-manager',
            name: 'James Wilson',
            subtitle: 'Engineering Manager',
            icon: 'fa-users-cog',
            tooltip: 'Manages development teams',
            color: '#e74c3c'
          }
        ]
      },
      {
        id: 'cfo',
        name: 'Jennifer Davis',
        subtitle: 'Chief Financial Officer',
        icon: 'fa-chart-line',
        tooltip: 'CFO managing financial strategy',
        color: '#27ae60'
      }
    ]
  });

  showcaseOptions = signal<AXHierarchyChartOption>({
    direction: 'vertical',
    width: 800,
    height: 600,
    nodeWidth: 180,
    nodeHeight: 70,
    nodeStrokeWidth: 2,
    linkWidth: 2,
    linkStyle: 'curved',
    nodeSpacingX: 100,
    nodeSpacingY: 140,
    collapsible: true,
    expandAll: false,
    margin: { top: 50, right: 50, bottom: 50, left: 50 }
  });

  onNodeClick(event: AXHierarchyChartClickEvent): void {
    const node = event.item;
    console.log('Node clicked:', node.name, node.subtitle);
  }
}
